+  const sql = "SELECT * FROM users WHERE name = '" + name + "'";
+  return db.query(sql);
+}

diff --git a/src/users.js b/src/users.js
--- a/src/users.js
+++ b/src/users.js
@@ -10,6 +10,9 @@
+export async function findUser(name, db) {
